mapper.select:
SELECT p.id, p.forum_id, p.user_id, p.title, p.summary, p.type, p.status, p.view_count, p.like_count, p.comment_count, p.collect_count, p.is_top, p.is_essence, p.last_reply_time, p.cover_image, p.create_time, p.ip_location, u.nickname AS user_name, u.avatar AS user_avatar, f.name AS forum_name FROM post p LEFT JOIN user u ON p.user_id = u.id LEFT JOIN forum f ON p.forum_id = f.id WHERE p.delete_flag = 0
AND p.status = #{query.status}
AND p.forum_id = #{query.forumId}
AND p.user_id = #{query.userId}
AND p.type = #{query.type}
AND p.is_top = #{query.isTop}
AND p.is_essence = #{query.isEssence}
AND p.audit_status = #{query.auditStatus}
AND EXISTS ( SELECT 1 FROM post_tag pt WHERE pt.post_id = p.id AND pt.tag_id = #{query.tagId} )
ORDER BY p.last_reply_time DESC, p.create_time DESC
ORDER BY (p.view_count + p.like_count * 5 + p.comment_count * 10) DESC, p.create_time DESC
ORDER BY p.comment_count DESC, p.create_time DESC
ORDER BY p.like_count DESC, p.create_time DESC
ORDER BY p.is_top DESC, p.create_time DESC

SELECT p.id, p.forum_id, p.user_id, p.title, p.summary, p.type, p.status, p.view_count, p.like_count, p.comment_count, p.collect_count, p.is_top, p.is_essence, p.last_reply_time, p.cover_image, p.create_time, p.ip_location, u.nickname AS user_name, u.avatar AS user_avatar, f.name AS forum_name FROM post p LEFT JOIN user u ON p.user_id = u.id LEFT JOIN forum f ON p.forum_id = f.id WHERE p.delete_flag = 0 AND p.status = 1 AND ( p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%') )
AND p.forum_id = #{query.forumId}
ORDER BY p.is_top DESC, p.create_time DESC

